import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { toast, ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import Header from './Header';

const API_ENDPOINTS = [
  {
    name: 'Save RFID Transaction Details',
    endpoint: 'SaveRFIDGunBarCodeTransactionDetails',
    method: 'POST',
    authRequired: true,
    icon: 'fas fa-save',
    sampleBody: [
      {
        "client_code": "", // Will be filled dynamically
        "RFIDNumber": "RFID001",
        "Itemcode": "ITEM001",
        "category_id": "Gold",
        "product_id": "Necklace",
        "design_id": "Fancy Design",
        "purity_id": "22KT",
        "grosswt": "15.000",
        "stonewt": "0.500",
        "diamondWeight": "0.200",
        "netwt": "14.300",
        "box_details": "Box 1",
        "size": "Medium",
        "stoneamount": "200",
        "diamondAmount": "500",
        "HallmarkAmount": "150",
        "MakingPerGram": "30",
        "MakingFixedAmt": "50",
        "MakingPercentage": "10",
        "MRP": "20000",
        "imageurl": "https://example.com/image.jpg",
        "status": "ApiActive"
      }
    ]
  },
  {
    name: 'Update RFID Transaction Details',
    endpoint: 'UpdateRFIDGunBarCodeTransactionDetails',
    method: 'POST',
    authRequired: true,
    icon: 'fas fa-edit',
    sampleBody: [
      {
        "client_code": "", // Will be filled dynamically
        "RFIDNumber": "RFID001",
        "status": "Sold"
      }
    ]
  },
  {
    name: 'Get RFID Transaction Details',
    endpoint: 'GetRFIDGunBarCodeTransactionDetails',
    method: 'POST',
    authRequired: true,
    icon: 'fas fa-search',
    sampleBody: {
      "client_code": "", // Will be filled dynamically
      "status": "ApiActive"
    }
  },
  {
    name: 'Delete Labelled Stock Items',
    endpoint: 'DeleteLabelledStockItems',
    method: 'POST',
    authRequired: true,
    icon: 'fas fa-trash',
    sampleBody: {
      "ClientCode": "", // Will be filled dynamically
      "ItemCodes": ["ITEM001", "ITEM002", "ITEM003"]
    }
  }
];

const Dashboard = () => {
  const [selectedApi, setSelectedApi] = useState(null);
  const [requestBody, setRequestBody] = useState('');
  const [response, setResponse] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [userInfo, setUserInfo] = useState(null);
  const [token, setToken] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    const storedToken = localStorage.getItem('token');
    const storedUserInfo = localStorage.getItem('userInfo');
    
    if (!storedToken) {
      navigate('/login');
      return;
    }

    setToken(storedToken);
    if (storedUserInfo) {
      const parsedUserInfo = JSON.parse(storedUserInfo);
      setUserInfo(parsedUserInfo);
    }
  }, [navigate]);

  const handleApiSelect = (api) => {
    setSelectedApi(api);
    // Create a deep copy of the sample body and inject the client code
    let sampleBodyCopy = JSON.parse(JSON.stringify(api.sampleBody));
    
    // Handle both array and object sample bodies
    if (Array.isArray(sampleBodyCopy)) {
      sampleBodyCopy = sampleBodyCopy.map(item => ({
        ...item,
        client_code: userInfo?.ClientCode || '',
        ClientCode: userInfo?.ClientCode || '' // For endpoints that use ClientCode
      }));
    } else {
      sampleBodyCopy = {
        ...sampleBodyCopy,
        client_code: userInfo?.ClientCode || '',
        ClientCode: userInfo?.ClientCode || '' // For endpoints that use ClientCode
      };
    }
    
    setRequestBody(JSON.stringify(sampleBodyCopy, null, 2));
    setResponse('');
    setError('');
  };

  const handleSendRequest = async () => {
    if (!selectedApi) return;

    setLoading(true);
    setError('');
    setResponse('');

    try {
      const config = {
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        }
      };

      const url = `https://soni.loyalstring.co.in/api/ProductMaster/${selectedApi.endpoint}`;
      let result;

      if (selectedApi.method === 'POST') {
        result = await axios.post(url, JSON.parse(requestBody), config);
      }

      setResponse(JSON.stringify(result.data, null, 2));
      toast.success('API request successful!');
    } catch (err) {
      const errorMessage = err.response?.data || err.message || 'An error occurred while making the request.';
      setError(errorMessage);
      toast.error(errorMessage);
      
      if (err.response?.status === 401) {
        toast.error('Authentication failed. Please login again.');
        localStorage.removeItem('token');
        localStorage.removeItem('userInfo');
        navigate('/login');
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="d-flex flex-column min-vh-100">
      <Header userInfo={userInfo} />
      <ToastContainer />
      <div className="container-fluid flex-grow-1 p-4">
        <div className="row h-100">
          <div className="col-md-3">
            <div className="card h-100" style={{ 
              background: 'linear-gradient(135deg, #ffffff 0%, #f8f9fa 100%)',
              boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
            }}>
              <div className="card-header bg-white">
                <h5 className="mb-0">
                  <i className="fas fa-list me-2"></i>
                  API Endpoints
                </h5>
              </div>
              <div className="list-group list-group-flush">
                {API_ENDPOINTS.map((api, index) => (
                  <button
                    key={index}
                    className={`list-group-item list-group-item-action ${
                      selectedApi?.endpoint === api.endpoint ? 'active' : ''
                    }`}
                    onClick={() => handleApiSelect(api)}
                  >
                    <div className="d-flex align-items-center">
                      <i className={`${api.icon} me-2`}></i>
                      {api.name}
                      {api.authRequired && (
                        <span className="badge bg-warning ms-2">
                          <i className="fas fa-lock me-1"></i>
                          Auth Required
                        </span>
                      )}
                    </div>
                  </button>
                ))}
              </div>
            </div>
          </div>
          <div className="col-md-9">
            {selectedApi ? (
              <div className="card h-100" style={{ 
                background: 'linear-gradient(135deg, #ffffff 0%, #f8f9fa 100%)',
                boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
              }}>
                <div className="card-header bg-white">
                  <div className="d-flex justify-content-between align-items-center">
                    <div>
                      <h5 className="mb-0">
                        <i className={`${selectedApi.icon} me-2`}></i>
                        {selectedApi.name}
                      </h5>
                      <small className="text-muted">
                        {selectedApi.method} /api/ProductMaster/{selectedApi.endpoint}
                      </small>
                    </div>
                    <div className="d-flex align-items-center">
                      <i className="fas fa-key me-2 text-warning"></i>
                      <small className="text-muted">Bearer Token: {token.substring(0, 20)}...</small>
                    </div>
                  </div>
                </div>
                <div className="card-body">
                  <div className="mb-3">
                    <label className="form-label">
                      <i className="fas fa-code me-2"></i>
                      Request Body
                    </label>
                    <textarea
                      className="form-control font-monospace"
                      rows="10"
                      value={requestBody}
                      onChange={(e) => setRequestBody(e.target.value)}
                    />
                  </div>
                  <button
                    className="btn btn-primary"
                    onClick={handleSendRequest}
                    disabled={loading}
                  >
                    {loading ? (
                      <>
                        <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
                        Sending...
                      </>
                    ) : (
                      <>
                        <i className="fas fa-paper-plane me-2"></i>
                        Send Request
                      </>
                    )}
                  </button>
                  {error && (
                    <div className="alert alert-danger mt-3">
                      <i className="fas fa-exclamation-circle me-2"></i>
                      {error}
                    </div>
                  )}
                  {response && (
                    <div className="mt-3">
                      <label className="form-label">
                        <i className="fas fa-reply me-2"></i>
                        Response
                      </label>
                      <pre className="bg-light p-3 rounded">
                        <code>{response}</code>
                      </pre>
                    </div>
                  )}
                </div>
              </div>
            ) : (
              <div className="card h-100 d-flex align-items-center justify-content-center" style={{ 
                background: 'linear-gradient(135deg, #ffffff 0%, #f8f9fa 100%)',
                boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
              }}>
                <div className="text-center">
                  <i className="fas fa-rfid fa-3x text-primary mb-3"></i>
                  <h4>Select an API endpoint to get started</h4>
                  <p className="text-muted">Choose an endpoint from the sidebar to begin testing</p>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
